import { useEffect, useRef } from "react";
import { Link } from "react-router-dom";
import "../styles/Home.css";

function Home() {
  const glowRef = useRef(null);

  useEffect(() => {
    // Scroll Reveal Observer
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('reveal-visible');
        }
      });
    }, { threshold: 0.1 });

    document.querySelectorAll('.reveal-on-scroll').forEach(el => observer.observe(el));

    // Mouse Glow Tracker
    const handleMouseMove = (e) => {
      if (glowRef.current) {
        glowRef.current.style.setProperty('--x', `${e.clientX}px`);
        glowRef.current.style.setProperty('--y', `${e.clientY}px`);
      }
    };

    window.addEventListener('mousemove', handleMouseMove);

    return () => {
      observer.disconnect();
      window.removeEventListener('mousemove', handleMouseMove);
    };
  }, []);

  return (
    <div className="home-container" ref={glowRef}>
      <div className="mouse-glow"></div>

      {/* Hero Section */}
      <section className="hero-section">
        <div className="hero-parallax-bg" style={{ backgroundImage: `url('/home_bg.png')` }}></div>
        <div className="hero-overlay-mesh"></div>

        <div className="hero-content">
          <div className="cinematic-hero">
            <div className="hero-badge">2026 ELITE PROTOCO ENABLED</div>
            <h1 className="hero-title">
              THE ART OF <span className="text-glow">CRICKET</span>
            </h1>
            <p className="hero-description">
              Precision data meets cinematic experience. Redefining how you analyze, 
              compare, and experience the elite champions of the game.
            </p>
            <div className="hero-cta">
              <Link to="/rankings" className="btn-primary">EXPLORE RANKINGS</Link>
              <Link to="/compare" className="btn-secondary">BATTLE ARENA</Link>
            </div>
          </div>
        </div>

        <div className="kinetic-ticker-wrapper">
          <div className="hero-stats-ticker">
            <div className="ticker-item">LIVE DATA FEED <span className="dot"></span></div>
            <div className="ticker-item">NEURAL ANALYTICS <span className="dot"></span></div>
            <div className="ticker-item">2026 PROJECTIONS <span className="dot"></span></div>
            <div className="ticker-item">ELITE SQUAD OPS <span className="dot"></span></div>
            <div className="ticker-item">LIVE DATA FEED <span className="dot"></span></div>
            <div className="ticker-item">NEURAL ANALYTICS <span className="dot"></span></div>
          </div>
        </div>
      </section>

      {/* Bento Features Grid */}
      <section className="bento-section reveal-on-scroll">
        <div className="section-header">
          <span className="subtitle">SYSTEM MODULES</span>
          <h2>FORGE YOUR STRATEGY</h2>
        </div>

        <div className="bento-grid">
          {/* Main Showcase Bento */}
          <div className="bento-item showcase-bento glass-card">
            <img src="/roko.jpg" alt="Showcase" className="bento-img" />
            <div className="bento-overlay">
              <span className="tag">FEATURED LEGENDS</span>
              <h3>THE ROKO ERA</h3>
              <p>Witness the peak of modern batting through raw data.</p>
              <Link to="/players" className="bento-btn">GO TO ROSTER</Link>
            </div>
          </div>

          {/* AI Bento */}
          <div className="bento-item ai-bento glass-card">
            <div className="bento-icon">🤖</div>
            <h3>AI ENGINE</h3>
            <p>Direct access to our proprietary analytics bot.</p>
            <Link to="/chat" className="bento-link">INITIALIZE →</Link>
          </div>

          {/* Battle Bento */}
          <div className="bento-item battle-bento glass-card">
            <div className="bento-icon">⚔️</div>
            <h3>BATTLE MODE</h3>
            <p>1v1 Data showdown.</p>
            <Link to="/compare" className="bento-link">ENTER ARENA →</Link>
          </div>

          {/* Stats Bento */}
          <div className="bento-item stats-bento glass-card">
            <div className="bento-icon">📊</div>
            <h3>GLOBAL STATS</h3>
            <p>Real-time tournament tracking.</p>
            <Link to="/stats" className="bento-link">VIEW DATA →</Link>
          </div>
        </div>
      </section>

      {/* Footer Branding */}
      <footer className="home-footer">
        <div className="footer-glow"></div>
        <p>© 2026 CRICSTATS ELITE • DEFINING THE STANDARD</p>
      </footer>
    </div>
  );
}

export default Home;
